features.snippet:
logic clk, _GEN;
always_ff @(posedge clk)
  assert property (disable iff (_GEN) 1'h1);

logic clk;
sequence seq_a;
  @(posedge clk) 1'h0;
endsequence
sequence seq_b;
  @(posedge clk) $rose(clk);
endsequence
assert property (seq_a |-> seq_b);

logic clk, req;
sequence seq_req;
  @(posedge clk) req;
endsequence
assert property (seq_req |-> 1'h1);
